import moment from "moment";
import { useRef, useState, useEffect } from "react";

export const ElapsedTimer = ({ date }) => {
  let [time, setTime] = useState(date ? diffYMDHMS(moment(date)) : "");
  let timRef = useRef();
  useEffect(() => {
    if (date) {
      timRef.current = setInterval(() => {
        setTime(diffYMDHMS(moment(date)));
      }, 1000 * 60);
    }

    return () => {
      if (timRef.current) {
        clearInterval(timRef.current);
      }
    };
  });
  return time;
};

const diffYMDHMS = (date2) => {
  let date1 = moment(new Date());
  let years = date1.diff(date2, "year");
  date2.add(years, "years");

  let months = date1.diff(date2, "months");
  date2.add(months, "months");

  let days = date1.diff(date2, "days");
  date2.add(days, "days");

  let hours = date1.diff(date2, "hours");
  date2.add(hours, "hours");

  let minutes = date1.diff(date2, "minutes");
  date2.add(minutes, "minutes");
  let res =
    buildStringFromValues(years, "Year") +
    " " +
    buildStringFromValues(months, "Month") +
    " " +
    buildStringFromValues(days, "Day") +
    " " +
    buildStringFromValues(hours, "Hr") +
    " " +
    buildStringFromValues(minutes, "Min");
  if (res.trim()) {
    return res;
  } else {
    return "Just now";
  }
};
const buildStringFromValues = (num, word) => {
  if (!num) {
    return "";
  }
  return num + " " + (num === 1 ? word : word + "s");
};
